import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.DL0AyVxm.js";const u=JSON.parse('{"title":"Agents","description":"","frontmatter":{},"headers":[],"relativePath":"reference/agents.md","filePath":"reference/agents.md"}'),n={name:"reference/agents.md"};function o(i,t,s,l,c,h){return d(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="agents" tabindex="-1">Agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;Agents&quot;">​</a></h1><p>Worclaude installs Claude Code agent definitions as Markdown files in <code>.claude/agents/</code>. Each agent has a specific model, isolation mode, and purpose. Universal agents are always installed. Optional agents are selected during <code>worclaude init</code> based on project type.</p><h2 id="agent-properties" tabindex="-1">Agent Properties <a class="header-anchor" href="#agent-properties" aria-label="Permalink to &quot;Agent Properties&quot;">​</a></h2><p>Every agent file includes a YAML frontmatter block with three fields:</p><table tabindex="0"><thead><tr><th>Property</th><th>Values</th><th>Meaning</th></tr></thead><tbody><tr><td><code>model</code></td><td><code>opus</code>, <code>sonnet</code>, <code>haiku</code></td><td>Which Claude model the agent uses</td></tr><tr><td><code>isolation</code></td><td><code>none</code>, <code>worktree</code></td><td>Whether the agent works in a git worktree</td></tr></tbody></table><h3 id="model-selection" tabindex="-1">Model Selection <a class="header-anchor" href="#model-selection" aria-label="Permalink to &quot;Model Selection&quot;">​</a></h3><p>Each agent is assigned a model based on the complexity and nature of its task:</p><table tabindex="0"><thead><tr><th>Model</th><th>Token Cost</th><th>Best For</th><th>Agents Using It</th></tr></thead><tbody><tr><td><strong>Opus</strong></td><td>Highest</td><td>Deep judgment, architectural decisions, security analysis</td><td>plan-reviewer, api-designer, auth-auditor, security-reviewer, prompt-engineer</td></tr><tr><td><strong>Sonnet</strong></td><td>Medium</td><td>Implementation, code changes, testing, documentation</td><td>code-simplifier, test-writer, verify-app, database-analyst, ui-reviewer, ci-fixer, docker-helper, deploy-validator, performance-auditor, bug-fixer, refactorer, doc-writer, data-pipeline-reviewer, ml-experiment-tracker</td></tr><tr><td><strong>Haiku</strong></td><td>Lowest</td><td>Narrow validation, formatting, simple checks</td><td>build-validator, style-enforcer, dependency-manager, changelog-generator</td></tr></tbody></table><h3 id="isolation-modes" tabindex="-1">Isolation Modes <a class="header-anchor" href="#isolation-modes" aria-label="Permalink to &quot;Isolation Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>How It Works</th><th>When Used</th></tr></thead><tbody><tr><td><strong>none</strong></td><td>Agent works in the current working directory alongside the user. Changes are made directly to the working tree.</td><td>Read-only review tasks, validation, analysis. No risk of conflicting with user changes.</td></tr><tr><td><strong>worktree</strong></td><td>Agent creates an isolated git worktree from the current branch. All changes happen in the worktree. User reviews and merges results afterward.</td><td>Code modification tasks (writing tests, fixing bugs, refactoring). Prevents conflicts with uncommitted user work. Requires clean git state to create the worktree.</td></tr></tbody></table><p>Agents with worktree isolation: code-simplifier, test-writer, verify-app, ci-fixer, bug-fixer, refactorer, doc-writer.</p><hr><h2 id="universal-agents" tabindex="-1">Universal Agents <a class="header-anchor" href="#universal-agents" aria-label="Permalink to &quot;Universal Agents&quot;">​</a></h2><p>These 5 agents are installed with every Worclaude project. They cover the core development workflow: planning, coding, testing, building, and verifying.</p><h3 id="plan-reviewer" tabindex="-1">plan-reviewer <a class="header-anchor" href="#plan-reviewer" aria-label="Permalink to &quot;plan-reviewer&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>opus</td></tr><tr><td><strong>Isolation</strong></td><td>none</td></tr><tr><td><strong>Invoked by</strong></td><td><code>/review-plan</code> slash command</td></tr></tbody></table><p>Acts as a senior staff engineer reviewing an implementation plan. Challenges assumptions, identifies ambiguity, checks for missing verification steps, and ensures the plan is specific enough for one-shot implementation. Validates alignment with <code>SPEC.md</code>. Does not approve plans that are vague or lack verification.</p><h3 id="code-simplifier" tabindex="-1">code-simplifier <a class="header-anchor" href="#code-simplifier" aria-label="Permalink to &quot;code-simplifier&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>sonnet</td></tr><tr><td><strong>Isolation</strong></td><td>worktree</td></tr></tbody></table><p>Reviews recently changed code and improves it. Finds and eliminates duplication, identifies reuse opportunities with existing code, simplifies complex logic, and ensures consistency with project patterns. Makes changes directly in a worktree and runs tests after each change. Commits improvements separately from feature work.</p><h3 id="test-writer" tabindex="-1">test-writer <a class="header-anchor" href="#test-writer" aria-label="Permalink to &quot;test-writer&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>sonnet</td></tr><tr><td><strong>Isolation</strong></td><td>worktree</td></tr></tbody></table><p>Writes comprehensive tests for recently changed code. Covers unit tests for individual functions, integration tests for component interactions, edge cases (null, empty, boundary values), and error paths. Follows the project&#39;s testing patterns from <code>.claude/skills/testing.md</code>. Aims for meaningful coverage rather than 100% line coverage.</p><h3 id="build-validator" tabindex="-1">build-validator <a class="header-anchor" href="#build-validator" aria-label="Permalink to &quot;build-validator&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>haiku</td></tr><tr><td><strong>Isolation</strong></td><td>none</td></tr></tbody></table><p>Validates that the project builds and passes all checks: build command, full test suite, linter, and type checker (if applicable). Reports failures with clear error messages. Does not fix issues -- reports them so the main session can address them. Used as a lightweight read-only validation step.</p><h3 id="verify-app" tabindex="-1">verify-app <a class="header-anchor" href="#verify-app" aria-label="Permalink to &quot;verify-app&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>sonnet</td></tr><tr><td><strong>Isolation</strong></td><td>worktree</td></tr><tr><td><strong>Invoked by</strong></td><td><code>/verify</code> slash command (indirectly)</td></tr></tbody></table><p>Tests the actual running application behavior, not just unit tests. Starts the application, tests changed functionality end-to-end, verifies behavior matches the specification, checks for regressions in related features, and tests error handling and edge cases in the running app. Reports specific pass/fail for each verification step.</p><hr><h2 id="optional-agents" tabindex="-1">Optional Agents <a class="header-anchor" href="#optional-agents" aria-label="Permalink to &quot;Optional Agents&quot;">​</a></h2><p>18 optional agents organized into 6 categories. During <code>worclaude init</code>, categories are recommended based on the selected project type.</p><h3 id="backend" tabindex="-1">Backend <a class="header-anchor" href="#backend" aria-label="Permalink to &quot;Backend&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>api-designer</code></td><td>opus</td><td>none</td><td>Reviews API design for RESTful conventions, consistency, and completeness.</td></tr><tr><td><code>database-analyst</code></td><td>sonnet</td><td>none</td><td>Reviews database schemas, queries, migrations, and indexing strategies.</td></tr><tr><td><code>auth-auditor</code></td><td>opus</td><td>none</td><td>Audits authentication and authorization implementations for security flaws.</td></tr></tbody></table><h3 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>ui-reviewer</code></td><td>sonnet</td><td>none</td><td>Reviews UI for visual consistency, accessibility, and responsive behavior.</td></tr><tr><td><code>style-enforcer</code></td><td>haiku</td><td>none</td><td>Ensures design system compliance across components and styles.</td></tr></tbody></table><h3 id="devops" tabindex="-1">DevOps <a class="header-anchor" href="#devops" aria-label="Permalink to &quot;DevOps&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>ci-fixer</code></td><td>sonnet</td><td>worktree</td><td>Diagnoses and fixes CI/CD pipeline failures.</td></tr><tr><td><code>docker-helper</code></td><td>sonnet</td><td>none</td><td>Reviews Docker configurations for best practices and optimization.</td></tr><tr><td><code>deploy-validator</code></td><td>sonnet</td><td>none</td><td>Validates deployment readiness including configs, environment variables, and dependencies.</td></tr><tr><td><code>dependency-manager</code></td><td>haiku</td><td>none</td><td>Reviews dependency health, outdated packages, and security advisories.</td></tr></tbody></table><h3 id="quality" tabindex="-1">Quality <a class="header-anchor" href="#quality" aria-label="Permalink to &quot;Quality&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>bug-fixer</code></td><td>sonnet</td><td>worktree</td><td>Diagnoses root causes and implements fixes for reported bugs.</td></tr><tr><td><code>security-reviewer</code></td><td>opus</td><td>none</td><td>Reviews code for security vulnerabilities, injection risks, and unsafe patterns.</td></tr><tr><td><code>performance-auditor</code></td><td>sonnet</td><td>none</td><td>Analyzes code for performance bottlenecks, memory leaks, and inefficiencies.</td></tr><tr><td><code>refactorer</code></td><td>sonnet</td><td>worktree</td><td>Refactors code to improve maintainability, readability, and structure.</td></tr></tbody></table><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>doc-writer</code></td><td>sonnet</td><td>worktree</td><td>Writes and updates project documentation including READMEs, guides, and API docs.</td></tr><tr><td><code>changelog-generator</code></td><td>haiku</td><td>none</td><td>Generates changelog entries from commit history.</td></tr></tbody></table><h3 id="data-ai" tabindex="-1">Data / AI <a class="header-anchor" href="#data-ai" aria-label="Permalink to &quot;Data / AI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Model</th><th>Isolation</th><th>Purpose</th></tr></thead><tbody><tr><td><code>data-pipeline-reviewer</code></td><td>sonnet</td><td>none</td><td>Reviews data pipeline correctness, schema consistency, and transformation logic.</td></tr><tr><td><code>ml-experiment-tracker</code></td><td>sonnet</td><td>none</td><td>Reviews ML experiment reproducibility, hyperparameter tracking, and result logging.</td></tr><tr><td><code>prompt-engineer</code></td><td>opus</td><td>none</td><td>Reviews and improves LLM prompts for clarity, specificity, and effectiveness.</td></tr></tbody></table><hr><h2 id="category-recommendations-by-project-type" tabindex="-1">Category Recommendations by Project Type <a class="header-anchor" href="#category-recommendations-by-project-type" aria-label="Permalink to &quot;Category Recommendations by Project Type&quot;">​</a></h2><p>During <code>worclaude init</code>, agent categories are pre-selected based on the chosen project type. Users can override these selections.</p><table tabindex="0"><thead><tr><th>Project Type</th><th>Recommended Categories</th></tr></thead><tbody><tr><td>Full-stack web application</td><td>Backend, Frontend, Quality, Documentation</td></tr><tr><td>Backend / API</td><td>Backend, Quality</td></tr><tr><td>Frontend / UI</td><td>Frontend, Quality</td></tr><tr><td>CLI tool</td><td>Quality, Documentation</td></tr><tr><td>Data / ML / AI</td><td>Data / AI, Backend</td></tr><tr><td>Library / Package</td><td>Quality, Documentation</td></tr><tr><td>DevOps / Infrastructure</td><td>DevOps</td></tr></tbody></table><h3 id="recommended-agents-per-project-type" tabindex="-1">Recommended Agents per Project Type <a class="header-anchor" href="#recommended-agents-per-project-type" aria-label="Permalink to &quot;Recommended Agents per Project Type&quot;">​</a></h3><p>The following table shows the specific agents recommended for each project type:</p><table tabindex="0"><thead><tr><th>Project Type</th><th>Recommended Agents</th></tr></thead><tbody><tr><td>Full-stack web application</td><td>ui-reviewer, api-designer, database-analyst, security-reviewer, bug-fixer, doc-writer</td></tr><tr><td>Backend / API</td><td>api-designer, database-analyst, security-reviewer, auth-auditor, bug-fixer, performance-auditor</td></tr><tr><td>Frontend / UI</td><td>ui-reviewer, style-enforcer, performance-auditor, bug-fixer</td></tr><tr><td>CLI tool</td><td>bug-fixer, doc-writer, dependency-manager</td></tr><tr><td>Data / ML / AI</td><td>data-pipeline-reviewer, ml-experiment-tracker, prompt-engineer, database-analyst</td></tr><tr><td>Library / Package</td><td>doc-writer, dependency-manager, performance-auditor, refactorer, changelog-generator</td></tr><tr><td>DevOps / Infrastructure</td><td>ci-fixer, docker-helper, deploy-validator, dependency-manager</td></tr></tbody></table><hr><h2 id="summary-table-all-23-agents" tabindex="-1">Summary Table (All 23 Agents) <a class="header-anchor" href="#summary-table-all-23-agents" aria-label="Permalink to &quot;Summary Table (All 23 Agents)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Category</th><th>Model</th><th>Isolation</th><th>Description</th></tr></thead><tbody><tr><td>plan-reviewer</td><td>Universal</td><td>opus</td><td>none</td><td>Reviews implementation plans as a staff engineer</td></tr><tr><td>code-simplifier</td><td>Universal</td><td>sonnet</td><td>worktree</td><td>Eliminates duplication, simplifies logic</td></tr><tr><td>test-writer</td><td>Universal</td><td>sonnet</td><td>worktree</td><td>Writes comprehensive tests for changed code</td></tr><tr><td>build-validator</td><td>Universal</td><td>haiku</td><td>none</td><td>Validates build, tests, lint without fixing</td></tr><tr><td>verify-app</td><td>Universal</td><td>sonnet</td><td>worktree</td><td>End-to-end application testing</td></tr><tr><td>api-designer</td><td>Backend</td><td>opus</td><td>none</td><td>Reviews API design for RESTful conventions</td></tr><tr><td>database-analyst</td><td>Backend</td><td>sonnet</td><td>none</td><td>Reviews database schemas and queries</td></tr><tr><td>auth-auditor</td><td>Backend</td><td>opus</td><td>none</td><td>Audits authentication and authorization</td></tr><tr><td>ui-reviewer</td><td>Frontend</td><td>sonnet</td><td>none</td><td>Reviews UI for consistency and accessibility</td></tr><tr><td>style-enforcer</td><td>Frontend</td><td>haiku</td><td>none</td><td>Ensures design system compliance</td></tr><tr><td>ci-fixer</td><td>DevOps</td><td>sonnet</td><td>worktree</td><td>Diagnoses and fixes CI/CD failures</td></tr><tr><td>docker-helper</td><td>DevOps</td><td>sonnet</td><td>none</td><td>Reviews Docker configs for best practices</td></tr><tr><td>deploy-validator</td><td>DevOps</td><td>sonnet</td><td>none</td><td>Validates deployment readiness</td></tr><tr><td>dependency-manager</td><td>DevOps</td><td>haiku</td><td>none</td><td>Reviews dependency health and updates</td></tr><tr><td>bug-fixer</td><td>Quality</td><td>sonnet</td><td>worktree</td><td>Diagnoses and fixes bugs</td></tr><tr><td>security-reviewer</td><td>Quality</td><td>opus</td><td>none</td><td>Reviews code for security vulnerabilities</td></tr><tr><td>performance-auditor</td><td>Quality</td><td>sonnet</td><td>none</td><td>Analyzes code for performance issues</td></tr><tr><td>refactorer</td><td>Quality</td><td>sonnet</td><td>worktree</td><td>Refactors code to improve maintainability</td></tr><tr><td>doc-writer</td><td>Documentation</td><td>sonnet</td><td>worktree</td><td>Writes and updates documentation</td></tr><tr><td>changelog-generator</td><td>Documentation</td><td>haiku</td><td>none</td><td>Generates changelog from commits</td></tr><tr><td>data-pipeline-reviewer</td><td>Data / AI</td><td>sonnet</td><td>none</td><td>Reviews data pipeline correctness</td></tr><tr><td>ml-experiment-tracker</td><td>Data / AI</td><td>sonnet</td><td>none</td><td>Reviews ML experiment reproducibility</td></tr><tr><td>prompt-engineer</td><td>Data / AI</td><td>opus</td><td>none</td><td>Reviews and improves LLM prompts</td></tr></tbody></table><hr><h2 id="agent-file-location" tabindex="-1">Agent File Location <a class="header-anchor" href="#agent-file-location" aria-label="Permalink to &quot;Agent File Location&quot;">​</a></h2><p>All agent files are installed to <code>.claude/agents/</code> as flat Markdown files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/agents/</span></span>
<span class="line"><span>  plan-reviewer.md          # universal</span></span>
<span class="line"><span>  code-simplifier.md        # universal</span></span>
<span class="line"><span>  test-writer.md            # universal</span></span>
<span class="line"><span>  build-validator.md        # universal</span></span>
<span class="line"><span>  verify-app.md             # universal</span></span>
<span class="line"><span>  api-designer.md           # optional (if selected)</span></span>
<span class="line"><span>  bug-fixer.md              # optional (if selected)</span></span>
<span class="line"><span>  ...</span></span></code></pre></div><p>Agent files can be customized after installation. The <code>worclaude diff</code> command tracks modifications, and <code>worclaude upgrade</code> preserves customizations by saving new versions as <code>.workflow-ref.md</code> files.</p><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/Worclaude/reference/slash-commands.html">Slash Commands</a> -- commands that invoke agents (e.g., <code>/review-plan</code>)</li><li><a href="/Worclaude/reference/skills.html">Skills</a> -- knowledge files that complement agent behavior</li><li><a href="/Worclaude/reference/claude-md.html">CLAUDE.md Template</a> -- how agents integrate with the session protocol</li></ul>`,62)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
